using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

// Optional: point to Azure OpenAI or any OpenAI-compatible endpoint.
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT");

// ---------------------------------------------------------------------------
// Shared state used by tools
// ---------------------------------------------------------------------------
var notes = new List<(string Title, string Content)>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(20);

// ---------------------------------------------------------------------------
// Tool definitions (automatically exposed to the model via MEAI)
// ---------------------------------------------------------------------------

[Description("Search the web for information on a topic. Returns a summary and related topics from DuckDuckGo.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
            + "&format=json&no_html=1&skip_disambig=1";

    var json = await httpClient.GetStringAsync(url);
    using var doc = JsonDocument.Parse(json);
    var root = doc.RootElement;

    var parts = new List<string>();

    // Main abstract (often from Wikipedia)
    var abs = root.GetProperty("Abstract").GetString();
    if (!string.IsNullOrWhiteSpace(abs))
    {
        var source = root.GetProperty("AbstractSource").GetString();
        var absUrl = root.GetProperty("AbstractURL").GetString();
        parts.Add($"**{source}**: {abs}\nURL: {absUrl}");
    }

    // Related topics
    if (root.TryGetProperty("RelatedTopics", out var topics))
    {
        foreach (var topic in topics.EnumerateArray().Take(8))
        {
            if (topic.TryGetProperty("Text", out var text))
            {
                var link = topic.TryGetProperty("FirstURL", out var u)
                    ? u.GetString() : null;
                parts.Add($"- {text.GetString()}"
                    + (link is not null ? $" ({link})" : ""));
            }
        }
    }

    return parts.Count > 0
        ? string.Join("\n", parts)
        : "No results found. Try different search terms or use ReadWebPage with a known URL.";
}

[Description("Fetch and return the text content of a web page at the given URL.")]
async Task<string> ReadWebPage(
    [Description("The full URL of the web page to read")] string url)
{
    try
    {
        var html = await httpClient.GetStringAsync(url);
        // Rough HTML-to-text conversion
        var text = Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ",
            RegexOptions.IgnoreCase);
        text = Regex.Replace(text, "<[^>]+>", " ");
        text = Regex.Replace(text, @"\s+", " ").Trim();

        const int limit = 5000;
        return text.Length > limit
            ? text[..limit] + "\n[Content truncated]"
            : text;
    }
    catch (Exception ex)
    {
        return $"Error fetching page: {ex.Message}";
    }
}

[Description("Save a research note for later reference.")]
string SaveNote(
    [Description("Short descriptive title")] string title,
    [Description("The note content / findings")] string content)
{
    notes.Add((title, content));
    return $"Note saved: \"{title}\" ({notes.Count} total).";
}

[Description("Retrieve all previously saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    return string.Join("\n---\n",
        notes.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
}

// ---------------------------------------------------------------------------
// Build the chat client with automatic function invocation
// ---------------------------------------------------------------------------
OpenAI.OpenAIClient openAiClient = endpoint is not null
    ? new(new ApiKeyCredential(apiKey), new OpenAI.OpenAIClientOptions { Endpoint = new Uri(endpoint) })
    : new(apiKey);

IChatClient client = new OpenAIChatClient(openAiClient.GetChatClient(model))
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(ReadWebPage),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// ---------------------------------------------------------------------------
// Conversation history with system prompt
// ---------------------------------------------------------------------------
List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a thorough research agent. When the user provides a topic:

        1. **Search** the web to find relevant information (try multiple queries).
        2. **Read** promising web pages to gather detailed facts.
        3. **Save** key findings as notes using the note-taking tool.
        4. After gathering enough information, **retrieve** your notes and produce
           a comprehensive, well-organized summary with citations.

        Always cite sources with URLs. Be accurate and concise.
        """),
];

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("══════════════════════════════════════");
Console.WriteLine("Enter a topic to research, or 'quit' to exit.");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("You > ");
    Console.ResetColor();

    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input)
        || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    history.Add(new ChatMessage(ChatRole.User, input));

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n  🔍 Researching… (this may take a moment)\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(history, chatOptions);
        history.AddMessages(response);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.Write("Agent > ");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("\nGoodbye! 👋");

