cd /tmp/check-types && cat > Program.cs << 'CSEOF'
using System;
using System.Linq;
using System.Reflection;

var asm = Assembly.Load("Microsoft.Extensions.AI.OpenAI");
Console.WriteLine("=== Exported types ===");
foreach (var type in asm.GetExportedTypes().OrderBy(x => x.FullName))
{
    Console.WriteLine(type.FullName);
    foreach (var m in type.GetMethods(BindingFlags.Public | BindingFlags.Static))
        if (m.DeclaringType == type)
            Console.WriteLine($"  .{m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
